let env = msg.payload;
let commands = [];

// Kural 1: Su Isınırsa Chiller'ı Aç
if (env.water_temp > 24.5) {
    commands.push({ payload: { "device": "chiller", "action": true } });
} else if (env.water_temp < 23.0) {
    commands.push({ payload: { "device": "chiller", "action": false } });
}

// Kural 2: pH Yükselirse Asit Pompala (pH Doser)
if (env.ph > 6.5) {
    commands.push({ payload: { "device": "ph_doser", "action": true } });
} else if (env.ph < 6.0) {
    commands.push({ payload: { "device": "ph_doser", "action": false } });
}

// Kural 3: Kabin Nemi %60'ı geçerse Nem Toplayıcıyı (Dehumidifier) aç
if (env.chamber_humidity > 60.0) {
    commands.push({ payload: { "device": "dehumidifier", "action": true } });
} else if (env.chamber_humidity < 50.0) {
    commands.push({ payload: { "device": "dehumidifier", "action": false } });
}

return [commands];
